  payload = '{"species": "Elder Tree", "species_slug": "elder-tree", "varieties": [{"name": "Sambucus australasica (Yellow Elderberry) 🌏 INDIGENOUS", "slug": "sambucus-australasica-yellow-elderberry-indigenous", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "sort_order": 0, "origin": "Endemic to eastern Australia (Queensland, New South Wales). Native to humid subtropical climates region coastal districts and rainforest margins.", "traits": "Shrub or small tree 2-5m tall. Pinnate leaves with 3-5 narrow elliptic leaflets, coarsely toothed. White flowers in large flat-topped clusters 10-20cm diameter.", "flesh_fruit": "", "yield_notes": "Moderate to good yields in suitable conditions. Berries ripen October-March.", "growing_notes": "", "availability": "Available from humid subtropical climates native plant nurseries, Queensland bushfood specialists. Lamington Native Nursery, local bushfood growers."}, {"name": "Black European Elderberry", "slug": "black-european-elderberry", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 1, "origin": "Europe, naturalized worldwide. Traditional hedgerow plant, centuries of cultivation.", "traits": "Deciduous shrub/small tree 3-6m tall. Dark green pinnate leaves. Large flat-topped clusters of creamy-white fragrant flowers.", "flesh_fruit": "", "yield_notes": "Heavy producer when established. Produces on 1-year-old wood.", "growing_notes": "", "availability": "Widely available humid subtropical climates nurseries: Ross Creek Tropicals, Daley''s Fruit Trees, Mr Fothergill''s, Garden Express, Food Forest Seeds Australia."}, {"name": "Black Beauty", "slug": "black-beauty", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 2, "origin": "UK, Horticulture Research International East Malling, 2001. Patent PP12,305.", "traits": "Upright dense shrub 2.5-3m tall and wide. Dark purple-red foliage, purple stems. Ornamental variety. Lemon-scented pink flowers in lar